## 4. Sample AWS CDK (TypeScript) – Secure, Immutable Security‑Tool Stack

```ts
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as config from 'aws-cdk-lib/aws-config';
import * as guardduty from 'aws-cdk-lib/aws-guardduty';
import * as securityhub from 'aws-cdk-lib/aws-securityhub';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as lambda from 'aws-cdk-lib/aws-lambda';
import * as events from 'aws-cdk-lib/aws-events';
import * as targets from 'aws-cdk-lib/aws-events-targets';

export class SecurityToolEnforcementStack extends Construct {
  constructor(scope: Construct, id: string) {
    super(scope, id);

    /* ---------- GuardDuty ---------- */
    const detector = new guardduty.CfnDetector(this, 'GuardDutyDetector', {
      enable: true,
    });

    /* ---------- Security Hub ---------- */
    const hub = new securityhub.CfnHub(this, 'SecurityHub', {
      enableDefaultStandards: true,
    });

    /* ---------- Config Rules ---------- */
    new config.CfnConfigRule(this, 'GuardDutyEnabledRule', {
      configRuleName: 'guardduty-enabled',
      source: {
        owner: 'AWS',
        sourceIdentifier: 'GUARD_DUTY_ENABLED',
      },
      inputParameters: {},
      maximumExecutionFrequency: 'TwentyFour_Hours',
    });

    new config.CfnConfigRule(this, 'SecurityHubEnabledRule', {
      configRuleName: 'securityhub-enabled',
      source: {
        owner: 'AWS',
        sourceIdentifier: 'SECURITY_HUB_ENABLED',
      },
      inputParameters: {},
      maximumExecutionFrequency: 'TwentyFour_Hours',
    });

    /* ---------- Lambda to Re‑enable Services ---------- */
    const reenableFn = new lambda.Function(this, 'ReenableSecurityTools', {
      runtime: lambda.Runtime.NODEJS_20_X,
      handler: 'index.handler',
      code: lambda.Code.fromInline(`
        const AWS = require('aws-sdk');
        const guardduty = new AWS.GuardDuty();
        const securityhub = new AWS.SecurityHub();

        exports.handler = async (event) => {
          // Re‑enable GuardDuty
          await guardduty.updateDetector({
            DetectorId: event.detectorId,
            Enable: true
          }).promise();

          // Re‑enable Security Hub
          await securityhub.updateHub({
            HubArn: event.hubArn,
            Enable: true
          }).promise();

          return { status: 'Re‑enabled' };
        };
      `),
      timeout: cdk.Duration.seconds(30),
      environment: {
        // Pass ARNs via environment or event
      },
    });

    /* ---------- EventBridge Rule to Trigger Lambda ---------- */
    const rule = new events.Rule(this, 'ConfigChangeRule', {
      eventPattern: {
        source: ['aws.config'],
        detailType: ['Config Configuration Item Change'],
        detail: {
          configurationItem: {
            resourceType: ['AWS::GuardDuty::Detector', 'AWS::SecurityHub::Hub'],
            configurationItemStatus: ['ResourceDeleted', 'ConfigurationItemStatusChanged'],
          },
        },
      },
    });

    rule.addTarget(new targets.LambdaFunction(reenableFn));

    /* ---------- IAM Policy for Lambda ---------- */
    reenableFn.addToRolePolicy(new iam.PolicyStatement({
      actions: [
        'guardduty:UpdateDetector',
        'securityhub:UpdateHub',
      ],
      resources: ['*'],
    }));
  }
}
```

### Secure‑by‑Design Highlights

| Pattern | Why it’s secure |
|---------|-----------------|
| **Least‑privilege IAM** – Lambda only has `guardduty:UpdateDetector` and `securityhub:UpdateHub`. | Limits attack surface. |
| **Immutable Config Rules** – Config rules are enforced continuously. | Prevents manual tampering. |
| **EventBridge + Lambda** – Automatic re‑enablement. | Removes human‑error window. |
| **No hard‑coded secrets** – Uses IAM roles. | Avoids credential leakage. |
| **Input validation** – Lambda expects only specific event structure. | Mitigates injection attacks. |

